//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "MCE round-tripping: preserving AlternateContent / unknown extension
//! markup through edit + accept/reject".
//!
//! Each `#[test]` encodes a Word-consumption or verbatim-preservation
//! post-condition mined from ISO/IEC 29500-1 §17.17.3 / §17.13.5 and
//! ISO/IEC 29500-3 §7.x/§9.x (Markup Compatibility & Extensibility). A FAILING
//! assertion here is NOT a test to be weakened: it encodes a real
//! Word-compliance gap in the stemma engine and should be triaged as such.
//!
//! Methodology guardrail (consumption vs. save):
//!   * `xmlContains` / `xmlOmits` are asserted on `reserialize()` and are only
//!     valid for markup stemma's serializer ACTIVELY emits or for its
//!     verbatim-preservation contract on UNTOUCHED markup (passthrough archive
//!     write). They are correct for "the original MCE markup survives the
//!     roundtrip / opens clean".
//!   * Word CONSUMPTION semantics (which Choice/Fallback branch the reader
//!     surfaces, accept/reject of tracked AC content) are asserted on the READ
//!     side: `read_accepted()` / `read_rejected()` `.to_text()`.

use stemma::ExportOptions;
use stemma::api::{Document, validate};

// ─── Prelude: minimal-.docx plumbing (mirrors the shared spec-suite prelude) ──

/// Build a valid minimal `.docx`. `body_xml` is placed verbatim inside
/// `<w:document …><w:body> … </w:body></w:document>` (so the caller supplies the
/// paragraphs / sectPr and any foreign-namespace declarations). `extra_parts`
/// are additional `(part_path, xml)` entries (e.g. `word/styles.xml`); each gets
/// a content-types Override inferred from its filename.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-types: defaults + document override + one override per extra part.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (path, _xml) in extra_parts {
        let content_type = if path.ends_with("styles.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        } else if path.ends_with("numbering.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        } else {
            panic!("make_docx: no known content-type for extra part {path}");
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{path}" ContentType="{content_type}"/>"#
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (path, xml) in extra_parts {
            zip.start_file(*path, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a string.
fn document_xml_of(docx: &[u8]) -> String {
    let mut zip = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("docx has word/document.xml");
    use std::io::Read;
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse → serialize (passthrough/verbatim for untouched markup) → return the
/// re-emitted `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// Assert `validate(bytes)` reports no errors (opens clean).
fn assert_opens_clean(bytes: &[u8], ctx: &str) {
    let report = validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{ctx} — expected the document to open clean (no validation errors), got ok={} issues={:?}",
        report.ok,
        report.issues
    );
}

fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
}

fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
}

