#[test]
fn untouched_ac_with_ignorable_list_survives_roundtrip_verbatim() {
    let body = r#"<w:p><mc:AlternateContent xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006" xmlns:wps="http://schemas.microsoft.com/office/word/2010/wordprocessingShape" xmlns:zz="http://stemma.example/ext" mc:Ignorable="zz"><mc:Choice Requires="wps"><w:r><w:t>CHOSEN</w:t></w:r></mc:Choice><mc:Fallback><w:r><w:t>FALLBACK</w:t></w:r></mc:Fallback></mc:AlternateContent></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"mc:Ignorable="zz""#),
        "ISO/IEC 29500-3 §7.2 + verbatim-preservation: the mc:Ignorable list the input carried must survive re-serialization unchanged. Missing `mc:Ignorable=\"zz\"` in:\n{xml}"
    );
    assert!(
        xml.contains("<mc:Fallback>"),
        "ISO/IEC 29500-1 §17.17.3: the non-taken Fallback branch must be roundtripped, not collapsed to just the selected Choice. Missing `<mc:Fallback>` in:\n{xml}"
    );
    assert!(
        xml.contains("FALLBACK"),
        "ISO/IEC 29500-1 §17.17.3: the Fallback branch payload must survive the roundtrip (non-taken-choice preservation). Missing `FALLBACK` in:\n{xml}"
    );
    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §7.5/§7.2: a preserved AlternateContent with an in-scope-bound mc:Ignorable list is conformant OOXML",
    );
}

#[test]
fn ac_in_del_reject_restores_accept_removes() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">before </w:t></w:r><w:del w:id="7" w:author="A" w:date="2026-06-14T00:00:00Z"><w:r><mc:AlternateContent xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006"><mc:Choice Requires="w"><w:t>CHOSEN</w:t></mc:Choice><mc:Fallback><w:t>FB</w:t></mc:Fallback></mc:AlternateContent></w:r></w:del><w:r><w:t xml:space="preserve"> after</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b).trim(),
        "before  after".trim(),
        "ECMA §17.13.5: accepting the deletion removes the deleted run (and its resolved AC), leaving only surrounding runs (§9.3/§9.4 MCE-before-revision)."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "before CHOSEN after".trim(),
        "ECMA §17.13.5 + §9.3/§9.4: rejecting the deletion restores prior content; MCE replaced the AC with the understood Choice (Requires='w'), so restored text is 'CHOSEN'."
    );
    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §7.5: a well-formed AC with declared mc namespace inside a valid w:del is conformant OOXML",
    );
}

#[test]
fn mc_ignorable_multitoken_list_survives_roundtrip() {
    let body = r#"<w:p><w:r xmlns:wps="http://schemas.microsoft.com/office/word/2010/wordprocessingShape" xmlns:w14="http://schemas.microsoft.com/office/word/2010/wordml" xmlns:wpg="http://schemas.microsoft.com/office/word/2010/wordprocessingGroup" mc:Ignorable="wps w14 wpg" xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006"><w:t>hello</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"mc:Ignorable="wps w14 wpg""#),
        "ISO/IEC 29500-3 §7.2 + §17.17.3: the full original multi-token Ignorable list must survive verbatim (passthrough preservation), never re-derived to a shorter list. Missing `mc:Ignorable=\"wps w14 wpg\"` in:\n{xml}"
    );
    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §7.2: all prefixes in the Ignorable list are bound to in-scope namespaces, so the document is conformant",
    );
}

#[test]
fn inline_ac_read_picks_choice_once_no_fallback_dup() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">A </w:t></w:r><mc:AlternateContent xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006"><mc:Choice Requires="w"><w:r><w:t>CHOICE</w:t></w:r></mc:Choice><mc:Fallback><w:r><w:t>FALLBACK</w:t></w:r></mc:Fallback></mc:AlternateContent><w:r><w:t xml:space="preserve"> B</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b).trim(),
        "A CHOICE B".trim(),
        "ISO/IEC 29500-3 §9.3/§9.4: MCE selects the understood Choice (Requires='w') and replaces the AC with its content only; the Fallback text must not appear. No tracked changes => accept == baseline."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "A CHOICE B".trim(),
        "ISO/IEC 29500-3 §9.3/§9.4: no revisions present, so reject equals the selected-branch reading; the Fallback still must not be surfaced."
    );
    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §7.5: a well-formed inline AC with Choice+Fallback is conformant",
    );
}

#[test]
fn ac_in_ins_unknown_choice_selects_fallback() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">x </w:t></w:r><w:ins w:id="9" w:author="A" w:date="2026-06-14T00:00:00Z"><w:r><mc:AlternateContent xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006" xmlns:futurens="http://schemas.example.com/never-understood/2099"><mc:Choice Requires="futurens"><w:t>NEVER</w:t></mc:Choice><mc:Fallback><w:t>FB</w:t></mc:Fallback></mc:AlternateContent></w:r></w:ins><w:r><w:t xml:space="preserve"> y</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b).trim(),
        "x FB y".trim(),
        "ISO/IEC 29500-3 §9.3: the unknown-ns Choice is skipped and the Fallback is selected; ECMA §17.13.5: accepting the insertion keeps the resolved Fallback text."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "x  y".trim(),
        "ECMA §17.13.5: rejecting the insertion removes the whole inserted run including the resolved AC content, leaving only surrounding runs."
    );
    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §7.5/§7.7: a well-formed AC (declared mc + unknown ns) inside a valid w:ins is conformant",
    );
}

#[test]
fn mce_ignorable_multi_token_list_survives_roundtrip() {
    let body = r#"<w:p><w:r><w:rPr><w:rPr xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006" xmlns:w14="http://schemas.microsoft.com/office/word/2010/wordml" xmlns:wp14="http://schemas.microsoft.com/office/word/2010/wordprocessingDrawing" mc:Ignorable="w14 wp14"><w14:glow w14:rad="63500"><w14:srgbClr w14:val="4F81BD"/></w14:glow></w:rPr></w:rPr><w:t>KEEP</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"mc:Ignorable="w14 wp14""#),
        "ISO/IEC 29500-3 §7.5: extension child legal only if its ns is ignorable; the full multi-token Ignorable list is verbatim-preserved markup and must be re-emitted unchanged. Missing `mc:Ignorable=\"w14 wp14\"` in:\n{xml}"
    );
    assert!(
        xml.contains("w14:glow"),
        "ISO/IEC 29500-1 §17.17.3: the extension element under the ignorable declaration must survive the roundtrip (verbatim passthrough). Missing `w14:glow` in:\n{xml}"
    );
    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §7.5: a run whose extension element namespace is declared ignorable is valid OOXML",
    );
}

#[test]
fn mce_choice_multi_prefix_requires_all_understood_else_skipped() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">before </w:t></w:r><mc:AlternateContent xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006" xmlns:w14="http://schemas.microsoft.com/office/word/2010/wordml" xmlns:zz="urn:totally-unknown-namespace-xyz"><mc:Choice Requires="w14 zz"><w:r><w:t>CHOICE</w:t></w:r></mc:Choice><mc:Fallback><w:r><w:t>FALLBACK</w:t></w:r></mc:Fallback></mc:AlternateContent><w:r><w:t xml:space="preserve"> after</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b).trim(),
        "before FALLBACK after".trim(),
        "ISO/IEC 29500-3 §9.3 (all-namespaces-must-be-understood): the Requires list contains unknown 'zz', so the Choice is not selectable and the Fallback is selected. No tracked changes => accept == baseline == Fallback."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "before FALLBACK after".trim(),
        "ISO/IEC 29500-3 §9.3/§9.4: no tracked changes, so reject equals the baseline consumption = the Fallback branch."
    );
    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §7.5/§7.6: a well-formed AC with a multi-prefix Requires and a Fallback is valid OOXML",
    );
}

#[test]
fn mce_choice_no_fallback_understood_requires_selects_choice() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">before </w:t></w:r><mc:AlternateContent xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006" xmlns:wps="http://schemas.microsoft.com/office/word/2010/wordprocessingShape"><mc:Choice Requires="wps"><w:r><w:t>ONLYCHOICE</w:t></w:r></mc:Choice></mc:AlternateContent><w:r><w:t xml:space="preserve"> after</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b).trim(),
        "before ONLYCHOICE after".trim(),
        "ISO/IEC 29500-3 §9.3 (select first understood Choice) + §9.4 (replace AC with selected content): the single Choice requires understood wps and is selected; with no Fallback the Choice content surfaces. No tracked changes => accept == baseline."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "before ONLYCHOICE after".trim(),
        "ISO/IEC 29500-3 §9.3/§9.4: no tracked changes, so reject equals the baseline = the selected Choice content."
    );
    assert_opens_clean(
        &b,
        "ISO/IEC 29500-3 §7.5: a Fallback-less AC is valid (Fallback is optional)",
    );
}

